const cfg = Array.isArray(msg.payload) ? msg.payload : [];
const prev = global.get("equipment_runtime") || {};
const next = {};
const allowedPushTopics = {};
const added = [];
const updated = [];
const removed = [];

function isValid(item) {
    if (!item || !item.equipment_id || !item.type || !item.protocol) return false;
    if (!item.endpoint || typeof item.endpoint !== "object") return false;
    if (item.type === "poll") {
        if (!(item.protocol === "modbus" || item.protocol === "opcua")) return false;
        if (!item.endpoint.host || !item.endpoint.port) return false;
        if (!item.poll_interval_sec || item.poll_interval_sec <= 0) return false;
    }
    if (item.type === "push") {
        if (item.protocol !== "mqtt") return false;
        if (!item.endpoint.host || !item.endpoint.port || !item.endpoint.topic) return false;
    }
    return true;
}

for (const item of cfg) {
    if (!isValid(item)) continue;
    const eid = item.equipment_id;
    const signature = JSON.stringify({
        equipment_id: item.equipment_id,
        type: item.type,
        protocol: item.protocol,
        endpoint: item.endpoint,
        poll_interval_sec: item.poll_interval_sec,
        mapping: item.mapping || {},
        timeout_sec: item.timeout_sec || 60
    });

    const prevEntry = prev[eid] || {};
    next[eid] = {
        config: item,
        signature,
        last_poll_ts: prevEntry.last_poll_ts || 0,
        alarm_until_ts: prevEntry.alarm_until_ts || 0,
        stable_until_ts: prevEntry.stable_until_ts || 0,
        current_raw: prevEntry.current_raw,
        last_emitted_status: prevEntry.last_emitted_status || null
    };

    if (!prev[eid]) added.push(eid);
    else if (prev[eid].signature !== signature) updated.push(eid);

    if (item.type === "push" && item.endpoint.topic) {
        allowedPushTopics[item.endpoint.topic] = {
            equipment_id: eid,
            mapping: item.mapping || {}
        };
    }
}

for (const oldId of Object.keys(prev)) {
    if (!next[oldId]) removed.push(oldId);
}

global.set("equipment_runtime", next);
global.set("allowed_push_topics", allowedPushTopics);

msg.payload = {
    total: Object.keys(next).length,
    added,
    updated,
    removed
};
return msg;

const runtime = global.get("equipment_runtime") || {};
const now = Date.now();
const events = [];

for (const eid of Object.keys(runtime)) {
    const entry = runtime[eid];
    const cfg = entry.config || {};
    if (cfg.type !== "poll") continue;

    const intervalMs = Math.max(1000, Number(cfg.poll_interval_sec || 2) * 1000);
    const lastTs = Number(entry.last_poll_ts || 0);
    if ((now - lastTs) < intervalMs) continue;
    entry.last_poll_ts = now;

    const statusMap = (cfg.mapping && cfg.mapping.status_map) || {"0":"STOP","1":"RUN","2":"ALARM"};

    const stableUntil = Number(entry.stable_until_ts || 0);
    let raw = Number(entry.current_raw);

    if (!Number.isFinite(raw) || now >= stableUntil) {
        const chance = Math.random();
        let durationMs;

        if (chance < 0.08) {
            raw = 2;
            durationMs = (Math.floor(Math.random() * 60) + 30) * 1000;
        } else if (chance < 0.30) {
            raw = 0;
            durationMs = (Math.floor(Math.random() * 40) + 20) * 1000;
        } else {
            raw = 1;
            durationMs = (Math.floor(Math.random() * 120) + 60) * 1000;
        }

        entry.current_raw = raw;
        entry.stable_until_ts = now + durationMs;
    }

    const status = statusMap[String(raw)] || (raw === 1 ? "RUN" : raw === 2 ? "ALARM" : "STOP");
    entry.last_emitted_status = status;
    events.push({
        equipment_id: eid,
        status,
        ts: new Date(now).toISOString(),
        payload: {
            source: cfg.protocol || "poll",
            endpoint: cfg.endpoint || {},
            raw
        }
    });
}

global.set("equipment_runtime", runtime);
msg.payload = events;
return msg;

const allowed = global.get("allowed_push_topics") || {};
const cfg = allowed[msg.topic];
if (!cfg) return null;

let rawValue = msg.payload;
let rawPayload = msg.payload;

if (typeof msg.payload === "string") {
    try {
        const obj = JSON.parse(msg.payload);
        rawPayload = obj;
        if (obj && typeof obj === "object") {
            rawValue = obj.status !== undefined ? obj.status : (obj.raw !== undefined ? obj.raw : msg.payload);
        }
    } catch (e) {
        rawValue = msg.payload;
    }
} else if (typeof msg.payload === "object" && msg.payload !== null) {
    rawPayload = msg.payload;
    rawValue = msg.payload.status !== undefined ? msg.payload.status : (msg.payload.raw !== undefined ? msg.payload.raw : msg.payload);
}

const statusMap = (cfg.mapping && cfg.mapping.status_map) || {};
let status = statusMap[String(rawValue)] || String(rawValue).toUpperCase();
if (!["RUN","STOP","IDLE","ALARM","OFFLINE"].includes(status)) {
    status = "STOP";
}

const runtime = global.get("equipment_runtime") || {};
const eid = cfg.equipment_id;
const entry = runtime[eid] || { config: { equipment_id: eid }, signature: "", last_poll_ts: 0, alarm_until_ts: 0 };
entry.last_emitted_status = status;
runtime[eid] = entry;
global.set("equipment_runtime", runtime);

msg.payload = {
    equipment_id: eid,
    status,
    ts: new Date().toISOString(),
    payload: {
        source: "mqtt",
        topic: msg.topic,
        raw: rawPayload
    }
};

return msg;
